import React, { useState, useEffect } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  BarChart3, 
  Users, 
  Code, 
  Database, 
  Cloud, 
  Rocket, 
  AlertCircle, 
  CheckCircle, 
  Clock, 
  Zap,
  TrendingUp,
  DollarSign,
  GitBranch,
  Server,
  HardDrive,
  MessageSquare,
  // Adding more icons for enhanced UI
  Plus,
  Eye,
  EyeOff,
  Trash2,
  Copy,
  Share2,
  Heart,
  ThumbsUp,
  ThumbsDown,
  Search,
  Filter,
  Grid,
  List,
  ExternalLink,
  Play,
  Square,
  RefreshCw,
  Settings,
  Edit3
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const pulse = keyframes`
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
`;

const fadeIn = keyframes`
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
`;

const float = keyframes`
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-5px); }
`;

const shimmer = keyframes`
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
`;

const Container = styled.div`
  padding: 2rem;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
  min-height: 100vh;
  position: relative;
  overflow: hidden;
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: radial-gradient(circle at center, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 70%);
    z-index: 0;
  }
`;

const Header = styled.div`
  margin-bottom: 2rem;
  position: relative;
  z-index: 1;
`;

const Title = styled.h1`
  font-size: 2rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const Subtitle = styled.p`
  color: #64748b;
  font-size: 1.1rem;
`;

const StatsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
  position: relative;
  z-index: 1;
`;

const StatCard = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 1.5rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.12);
  }
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: linear-gradient(90deg, #667eea, #764ba2);
  }
  
  @media (max-width: 768px) {
    padding: 1.25rem;
  }
`;

const StatHeader = styled.div`
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1rem;
`;

const StatIcon = styled.div`
  width: 3.5rem;
  height: 3.5rem;
  border-radius: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  animation: ${float} 3s ease-in-out infinite;
`;

const StatTitle = styled.h3`
  font-size: 1rem;
  font-weight: 500;
  color: #64748b;
  margin: 0;
`;

const StatValue = styled.div`
  font-size: 2rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const StatChange = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.9rem;
  font-weight: 500;
  
  &.positive {
    color: #10b981;
  }
  
  &.negative {
    color: #ef4444;
  }
`;

const Section = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 2rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  margin-bottom: 2rem;
  animation: ${fadeIn} 0.5s ease-out;
  position: relative;
  z-index: 1;
  
  @media (max-width: 768px) {
    padding: 1.5rem;
  }
`;

const SectionHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1.5rem;
  
  @media (max-width: 768px) {
    flex-direction: column;
    align-items: flex-start;
    gap: 1rem;
  }
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
`;

const ViewAllButton = styled.button`
  background: #f1f5f9;
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 0.5rem;
  font-size: 0.9rem;
  font-weight: 500;
  cursor: pointer;
  color: #1e293b;
  transition: all 0.2s ease;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  
  &:hover {
    background: #e2e8f0;
  }
  
  @media (max-width: 768px) {
    align-self: flex-end;
  }
`;

const Controls = styled.div`
  display: flex;
  gap: 1rem;
  align-items: center;
  
  @media (max-width: 768px) {
    width: 100%;
    justify-content: space-between;
  }
`;

const SearchInput = styled.input`
  padding: 0.5rem 1rem;
  border: 1px solid #e2e8f0;
  border-radius: 0.5rem;
  font-size: 0.9rem;
  
  &:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
  }
  
  @media (max-width: 768px) {
    flex: 1;
  }
`;

const FilterButton = styled.button`
  background: #f1f5f9;
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 0.5rem;
  font-size: 0.9rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  
  &:hover {
    background: #e2e8f0;
  }
`;

const ViewToggle = styled.div`
  display: flex;
  background: #f1f5f9;
  border-radius: 0.5rem;
  overflow: hidden;
`;

const ViewButton = styled.button`
  background: ${props => props.active ? 'white' : 'transparent'};
  border: none;
  padding: 0.5rem 1rem;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-weight: ${props => props.active ? '500' : 'normal'};
  
  &:hover {
    background: ${props => props.active ? 'white' : '#e2e8f0'};
  }
`;

const ProjectGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 1.5rem;
  margin-top: 1rem;
`;

const ProjectCard = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 1.5rem;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 1px solid #e2e8f0;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(102, 126, 234, 0.15);
    border-color: #667eea;
  }
  
  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: linear-gradient(90deg, #667eea, #764ba2);
  }
`;

const ProjectHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 1rem;
`;

const ProjectTitle = styled.h3`
  font-size: 1.25rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
`;

const ProjectFramework = styled.div`
  background: #f1f5f9;
  color: #64748b;
  padding: 0.25rem 0.75rem;
  border-radius: 2rem;
  font-size: 0.8rem;
  font-weight: 500;
  margin-top: 0.5rem;
  display: inline-block;
`;

const ProjectDetails = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
  margin-bottom: 1.5rem;
`;

const ProjectDetail = styled.div`
  display: flex;
  justify-content: space-between;
  font-size: 0.9rem;
  
  .label {
    color: #64748b;
  }
  
  .value {
    color: #1e293b;
    font-weight: 500;
  }
`;

const ProjectActionsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 0.75rem;
`;

const ProjectItem = styled.div`
  display: flex;
  align-items: center;
  padding: 1.25rem;
  border-radius: 0.75rem;
  border: 1px solid #e2e8f0;
  transition: all 0.2s ease;
  
  &:hover {
    background: #f8fafc;
    border-color: #c7d2fe;
  }
  
  @media (max-width: 768px) {
    flex-direction: column;
    align-items: flex-start;
    gap: 1rem;
  }
`;

const ProjectIcon = styled.div`
  width: 3rem;
  height: 3rem;
  border-radius: 0.75rem;
  background: #f1f5f9;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #64748b;
  margin-right: 1rem;
  
  @media (max-width: 768px) {
    margin-right: 0;
  }
`;

const ProjectInfo = styled.div`
  flex: 1;
  
  @media (max-width: 768px) {
    width: 100%;
  }
`;

const ProjectName = styled.h3`
  font-size: 1.1rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.25rem 0;
`;

const ProjectMeta = styled.div`
  display: flex;
  gap: 1rem;
  font-size: 0.875rem;
  color: #64748b;
  
  @media (max-width: 768px) {
    flex-direction: column;
    gap: 0.25rem;
  }
`;

const ProjectActions = styled.div`
  display: flex;
  gap: 0.75rem;
  
  @media (max-width: 768px) {
    width: 100%;
    justify-content: flex-end;
  }
`;

const ActionButton = styled.button`
  background: #f1f5f9;
  border: none;
  padding: 0.5rem 1rem;
  border-radius: 0.5rem;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  color: #1e293b;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e2e8f0;
  }
  
  &.primary {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    
    &:hover {
      opacity: 0.9;
    }
  }
  
  &.success {
    background: #10b981;
    color: white;
    
    &:hover {
      background: #059669;
    }
  }
  
  &.danger {
    background: #ef4444;
    color: white;
    
    &:hover {
      background: #dc2626;
    }
  }
  
  @media (max-width: 768px) {
    padding: 0.4rem 0.8rem;
    font-size: 0.8rem;
  }
`;

const StatusIndicator = styled.div`
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.25rem 0.75rem;
  border-radius: 2rem;
  font-size: 0.875rem;
  font-weight: 500;
  
  &.completed {
    background: #dcfce7;
    color: #16a34a;
  }
  
  &.in-progress {
    background: #fef3c7;
    color: #d97706;
  }
  
  &.failed {
    background: #fee2e2;
    color: #dc2626;
  }
`;

const QuickActions = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1rem;
  margin-top: 1.5rem;
`;

const ActionCard = styled.div`
  background: white;
  border-radius: 1rem;
  padding: 1.5rem;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 1px solid #e2e8f0;
  cursor: pointer;
  transition: all 0.3s ease;
  text-align: center;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(102, 126, 234, 0.15);
    border-color: #667eea;
  }
  
  @media (max-width: 768px) {
    padding: 1.25rem;
  }
`;

const ActionIcon = styled.div`
  width: 3rem;
  height: 3rem;
  border-radius: 0.75rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  margin: 0 auto 1rem;
  font-size: 1.5rem;
`;

const ActionTitle = styled.h3`
  font-size: 1.1rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.5rem 0;
`;

const ActionDescription = styled.p`
  color: #64748b;
  font-size: 0.9rem;
  margin: 0;
`;

function Dashboard() {
  const navigate = useNavigate();
  const [projects, setProjects] = useState([
    {
      id: 1,
      name: 'Analytics Dashboard',
      status: 'completed',
      createdAt: '2023-06-15',
      lastModified: '2023-06-18',
      framework: 'React + FastAPI',
      deployed: true,
      techStack: {
        frontend: 'React',
        backend: 'FastAPI',
        database: 'MySQL'
      },
      features: ['Charts & Graphs', 'Real-time Data', 'User Management'],
      previewUrl: 'https://dashboard-demo.example.com'
    },
    {
      id: 2,
      name: 'E-commerce Store',
      status: 'in-progress',
      createdAt: '2023-06-10',
      lastModified: '2023-06-17',
      framework: 'Vue + Express',
      deployed: false,
      techStack: {
        frontend: 'Vue.js',
        backend: 'Express.js',
        database: 'PostgreSQL'
      },
      features: ['Product Catalog', 'Shopping Cart', 'Payment Gateway'],
      previewUrl: null
    },
    {
      id: 3,
      name: 'Blog CMS',
      status: 'completed',
      createdAt: '2023-06-05',
      lastModified: '2023-06-12',
      framework: 'Angular + Django',
      deployed: true,
      techStack: {
        frontend: 'Angular',
        backend: 'Django',
        database: 'SQLite'
      },
      features: ['Rich Text Editor', 'SEO Tools', 'Media Management'],
      previewUrl: 'https://blog-demo.example.com'
    },
    {
      id: 4,
      name: 'Chat Application',
      status: 'failed',
      createdAt: '2023-06-01',
      lastModified: '2023-06-15',
      framework: 'React + NestJS',
      deployed: false,
      techStack: {
        frontend: 'React',
        backend: 'NestJS',
        database: 'MongoDB'
      },
      features: ['Real-time Chat', 'File Sharing', 'Push Notifications'],
      previewUrl: null
    }
  ]);
  
  const [stats, setStats] = useState({
    totalProjects: 12,
    activeProjects: 8,
    completedProjects: 9,
    totalDeployments: 15
  });
  
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState('list');
  const [filterStatus, setFilterStatus] = useState('all');

  const filteredProjects = projects.filter(project => {
    const matchesSearch = project.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = filterStatus === 'all' || project.status === filterStatus;
    return matchesSearch && matchesFilter;
  });

  const handleCreateNew = () => {
    navigate('/builder');
  };

  const handleViewDemo = (project) => {
    if (project.previewUrl) {
      window.open(project.previewUrl, '_blank');
    } else {
      // In a real implementation, this would show a preview modal or message
      alert('Demo not available for this project yet.');
    }
  };

  const handleViewProject = (projectId) => {
    // In a real implementation, this would navigate to the project details page
    console.log(`Viewing project ${projectId}`);
  };

  const handleDeployProject = (projectId) => {
    navigate('/deploy');
  };

  const handleDeleteProject = (projectId) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      setProjects(prev => prev.filter(project => project.id !== projectId));
    }
  };

  const handleEditProject = (projectId) => {
    // In a real implementation, this would navigate to the project edit page
    console.log(`Editing project ${projectId}`);
  };

  const getStatusText = (status) => {
    switch (status) {
      case 'completed':
        return 'Completed';
      case 'in-progress':
        return 'In Progress';
      case 'failed':
        return 'Failed';
      default:
        return 'Unknown';
    }
  };

  const quickActions = [
    {
      title: 'New Project',
      description: 'Create a new application from scratch',
      icon: Plus,
      action: handleCreateNew
    },
    {
      title: 'AI Chat',
      description: 'Chat with AI to build applications',
      icon: MessageSquare,
      action: () => navigate('/ai-chat')
    },
    {
      title: 'Deploy',
      description: 'Deploy your applications to the cloud',
      icon: Rocket,
      action: () => navigate('/deploy')
    },
    {
      title: 'Integrations',
      description: 'Connect third-party services',
      icon: GitBranch,
      action: () => navigate('/integrations')
    }
  ];

  return (
    <Container>
      <Header>
        <Title>Dashboard</Title>
        <Subtitle>Welcome back! Here's what's happening with your projects.</Subtitle>
      </Header>
      
      <StatsGrid>
        <StatCard>
          <StatHeader>
            <StatTitle>Total Projects</StatTitle>
            <StatIcon>
              <Code size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.totalProjects}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            12% from last month
          </StatChange>
        </StatCard>
        
        <StatCard>
          <StatHeader>
            <StatTitle>Active Projects</StatTitle>
            <StatIcon>
              <Zap size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.activeProjects}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            5% from last month
          </StatChange>
        </StatCard>
        
        <StatCard>
          <StatHeader>
            <StatTitle>Completed</StatTitle>
            <StatIcon>
              <CheckCircle size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.completedProjects}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            8% from last month
          </StatChange>
        </StatCard>
        
        <StatCard>
          <StatHeader>
            <StatTitle>Deployments</StatTitle>
            <StatIcon>
              <Rocket size={20} />
            </StatIcon>
          </StatHeader>
          <StatValue>{stats.totalDeployments}</StatValue>
          <StatChange className="positive">
            <TrendingUp size={16} />
            15% from last month
          </StatChange>
        </StatCard>
      </StatsGrid>
      
      <Section>
        <SectionHeader>
          <SectionTitle>Quick Actions</SectionTitle>
        </SectionHeader>
        
        <QuickActions>
          {quickActions.map((action, index) => (
            <ActionCard key={index} onClick={action.action}>
              <ActionIcon>
                <action.icon size={24} />
              </ActionIcon>
              <ActionTitle>{action.title}</ActionTitle>
              <ActionDescription>{action.description}</ActionDescription>
            </ActionCard>
          ))}
        </QuickActions>
      </Section>
      
      <Section>
        <SectionHeader>
          <SectionTitle>Your Projects</SectionTitle>
          <Controls>
            <SearchInput
              type="text"
              placeholder="Search projects..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
            <FilterButton onClick={() => setFilterStatus(filterStatus === 'all' ? 'completed' : 'all')}>
              <Filter size={16} />
              {filterStatus === 'all' ? 'Show Completed' : 'Show All'}
            </FilterButton>
            <ViewToggle>
              <ViewButton 
                active={viewMode === 'list'} 
                onClick={() => setViewMode('list')}
              >
                <List size={16} />
                List
              </ViewButton>
              <ViewButton 
                active={viewMode === 'grid'} 
                onClick={() => setViewMode('grid')}
              >
                <Grid size={16} />
                Grid
              </ViewButton>
            </ViewToggle>
            <ViewAllButton onClick={handleCreateNew}>
              <Plus size={16} />
              New Project
            </ViewAllButton>
          </Controls>
        </SectionHeader>
        
        <ProjectList>
          {viewMode === 'list' ? (
            filteredProjects.map(project => (
              <ProjectItem key={project.id}>
                <ProjectIcon>
                  <Code size={20} />
                </ProjectIcon>
                <ProjectInfo>
                  <ProjectName>{project.name}</ProjectName>
                  <ProjectMeta>
                    <span>{project.framework}</span>
                    <span>Created: {project.createdAt}</span>
                    <span>Modified: {project.lastModified}</span>
                  </ProjectMeta>
                </ProjectInfo>
                <ProjectActions>
                  <StatusIndicator className={project.status}>
                    {getStatusText(project.status)}
                  </StatusIndicator>
                  <ActionButton onClick={() => handleViewProject(project.id)}>
                    <Eye size={16} />
                    View
                  </ActionButton>
                  {project.previewUrl && (
                    <ActionButton 
                      className="success" 
                      onClick={() => handleViewDemo(project)}
                    >
                      <ExternalLink size={16} />
                      Demo
                    </ActionButton>
                  )}
                  {!project.deployed && (
                    <ActionButton 
                      className="primary" 
                      onClick={() => handleDeployProject(project.id)}
                    >
                      <Rocket size={16} />
                      Deploy
                    </ActionButton>
                  )}
                  <ActionButton onClick={() => handleEditProject(project.id)}>
                    <Edit3 size={16} />
                    Edit
                  </ActionButton>
                  <ActionButton 
                    className="danger" 
                    onClick={() => handleDeleteProject(project.id)}
                  >
                    <Trash2 size={16} />
                    Delete
                  </ActionButton>
                </ProjectActions>
              </ProjectItem>
            ))
          ) : (
            <ProjectGrid>
              {filteredProjects.map(project => (
                <ProjectCard key={project.id}>
                  <ProjectHeader>
                    <div>
                      <ProjectTitle>{project.name}</ProjectTitle>
                      <ProjectFramework>{project.framework}</ProjectFramework>
                    </div>
                    <StatusIndicator className={project.status}>
                      {getStatusText(project.status)}
                    </StatusIndicator>
                  </ProjectHeader>
                  
                  <ProjectDetails>
                    <ProjectDetail>
                      <span className="label">Created</span>
                      <span className="value">{project.createdAt}</span>
                    </ProjectDetail>
                    <ProjectDetail>
                      <span className="label">Last Modified</span>
                      <span className="value">{project.lastModified}</span>
                    </ProjectDetail>
                    <ProjectDetail>
                      <span className="label">Features</span>
                      <span className="value">{project.features.join(', ')}</span>
                    </ProjectDetail>
                  </ProjectDetails>
                  
                  <ProjectActionsGrid>
                    <ActionButton onClick={() => handleViewProject(project.id)}>
                      <Eye size={16} />
                      View
                    </ActionButton>
                    {project.previewUrl ? (
                      <ActionButton 
                        className="success" 
                        onClick={() => handleViewDemo(project)}
                      >
                        <ExternalLink size={16} />
                        Demo
                      </ActionButton>
                    ) : (
                      <ActionButton disabled>
                        <ExternalLink size={16} />
                        No Demo
                      </ActionButton>
                    )}
                    {!project.deployed && (
                      <ActionButton 
                        className="primary" 
                        onClick={() => handleDeployProject(project.id)}
                      >
                        <Rocket size={16} />
                        Deploy
                      </ActionButton>
                    )}
                    <ActionButton 
                      className="danger" 
                      onClick={() => handleDeleteProject(project.id)}
                    >
                      <Trash2 size={16} />
                      Delete
                    </ActionButton>
                  </ProjectActionsGrid>
                </ProjectCard>
              ))}
            </ProjectGrid>
          )}
        </ProjectList>
      </Section>
    </Container>
  );
}

export default Dashboard;
